// Make all fields optional for update
type UserUpdate = Partial<User>;

// Pick specific fields
type UserPreview = Pick<User, 'id' | 'name' | 'avatar'>;

// Omit sensitive fields
type PublicUser = Omit<User, 'password' | 'email'>;

// Record for dictionaries
type ErrorMap = Record<string, string[]>;

// Awaited for unwrapping promises
type Data = Awaited<ReturnType<typeof fetchUser>>;

// Custom: DeepPartial
type DeepPartial<T> = { [P in keyof T]?: T[P] extends object ? DeepPartial<T[P]> : T[P] };

// Custom: RequireAtLeastOne
type RequireAtLeastOne<T, Keys extends keyof T = keyof T> =
  Pick<T, Exclude<keyof T, Keys>> & { [K in Keys]-?: Required<Pick<T, K>> & Partial<Pick<T, Exclude<Keys, K>>> }[Keys];

// Discriminated union
type Result<T> = { ok: true; data: T } | { ok: false; error: string };

function handleResult<T>(result: Result<T>) {
  if (result.ok) {
    console.log(result.data); // narrowed to { ok: true; data: T }
  } else {
    console.error(result.error); // narrowed to { ok: false; error: string }
  }
}

// Custom type guard
function isUser(obj: unknown): obj is User {
  return typeof obj === 'object' && obj !== null && 'id' in obj && 'email' in obj;
}

// Assertion function
function assertDefined<T>(value: T | null | undefined, name: string): asserts value is T {
  if (value == null) throw new Error(`${name} is not defined`);
}

// Exhaustive check
function assertNever(x: never): never { throw new Error(`Unexpected value: ${x}`); }

// Constrained generic
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

// Generic factory
function createStore<T>(initial: T) {
  let state = initial;
  return {
    get: () => state,
    set: (next: T) => { state = next; },
    update: (fn: (prev: T) => T) => { state = fn(state); },
  };
}

// Conditional type
type IsArray<T> = T extends unknown[] ? true : false;
type Flatten<T> = T extends (infer U)[] ? U : T;

// Template literal types
type EventName = `on${Capitalize<'click' | 'focus' | 'blur'>}`; // 'onClick' | 'onFocus' | 'onBlur'

// Mapped type with transformation
type Getters<T> = { [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K] };

// Result type
type Result<T, E = Error> = { success: true; data: T } | { success: false; error: E };

async function trySafe<T>(fn: () => Promise<T>): Promise<Result<T>> {
  try {
    return { success: true, data: await fn() };
  } catch (e) {
    return { success: false, error: e instanceof Error ? e : new Error(String(e)) };
  }
}

// Custom error hierarchy
class AppError extends Error {
  constructor(message: string, public code: string, public statusCode: number = 500) {
    super(message);
    this.name = 'AppError';
  }
}

class NotFoundError extends AppError {
  constructor(resource: string) { super(`${resource} not found`, 'NOT_FOUND', 404); }
}

class ValidationError extends AppError {
  constructor(public fields: Record<string, string>) { super('Validation failed', 'VALIDATION', 400); }
}

import { z } from 'zod';

// Define schema
const UserSchema = z.object({
  name: z.string().min(2).max(100),
  email: z.string().email(),
  age: z.number().int().min(0).max(150).optional(),
  role: z.enum(['admin', 'user', 'moderator']).default('user'),
  tags: z.array(z.string()).default([]),
});

// Infer TypeScript type from schema
type User = z.infer<typeof UserSchema>;

// Parse (throws on invalid)
const user = UserSchema.parse(inputData);

// Safe parse (returns result)
const result = UserSchema.safeParse(inputData);
if (result.success) {
  console.log(result.data); // typed as User
} else {
  console.error(result.error.flatten());
}

